-- ============================================================
-- MIGRATION 000231 — Premium, brand-aware email templates
-- Pixie Girl Hub · JBS Praxis · V2.2
--
-- GENERATED by scripts/gen-premium-email-templates.js from the single skin in
-- src/services/email-theme.js. Do not hand-edit — re-run the generator.
--
-- Replaces the bare seeded templates (`<h1>Welcome!</h1>`) with one luxury,
-- table-based, inline-CSS, Outlook/Gmail/Apple-safe skin. All brand identity
-- (logo, accent colour, name, links, address) is left as {{tokens}} that the
-- send pipeline (email-render.js) fills per brand from Settings, so the same
-- template reskins itself for Pixie Girl Global vs Faitlynhair.
--
-- Adds email_campaigns.merge_data (campaign-level tokens: sale discount, link,
-- end date → the static countdown) and seeds a new `sale_announcement` template.
--
-- Idempotent: the installer upserts on template_key; safe to re-run.
-- ============================================================

CREATE OR REPLACE FUNCTION shared.fn_install_premium_email_templates(p_schema text)
RETURNS void
LANGUAGE plpgsql
AS $func$
DECLARE
  v_subject text;
  v_pre     text;
  v_html    text;
  v_text    text;
BEGIN
  -- welcome
  v_subject := $pgh$Welcome to {{brand_name}}, {{first_name}} ✨$pgh$;
  v_pre     := $pgh$You're now part of the {{brand_name}} community — here's what to expect.$pgh$;
  v_html    := $pgh$<!DOCTYPE html>
<html lang="en" xmlns:v="urn:schemas-microsoft-com:vml" xmlns:o="urn:schemas-microsoft-com:office:office">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<meta http-equiv="X-UA-Compatible" content="IE=edge">
<meta name="color-scheme" content="light only">
<meta name="supported-color-schemes" content="light only">
<title>{{brand_name}}</title>
<!--[if mso]><xml><o:OfficeDocumentSettings><o:PixelsPerInch>96</o:PixelsPerInch></o:OfficeDocumentSettings></xml><![endif]-->
<link rel="preconnect" href="https://fonts.googleapis.com">
<style>
  @import url('https://fonts.googleapis.com/css2?family=Montserrat:wght@400;500;600;700&family=Playfair+Display:ital,wght@0,500;0,600;0,700;1,500&display=swap');
  :root { color-scheme: light only; supported-color-schemes: light only; }
  body { margin:0; padding:0; width:100% !important; -webkit-text-size-adjust:100%; -ms-text-size-adjust:100%; }
  img { -ms-interpolation-mode:bicubic; }
  a { text-decoration:none; }
  @media only screen and (max-width:620px) {
    .pgh-card { width:100% !important; border-radius:0 !important; }
    .pgh-card td { padding-left:24px !important; padding-right:24px !important; }
  }
</style>
</head>
<body style="margin:0;padding:0;background-color:#F4EFE9">
  <div style="display:none;max-height:0;overflow:hidden;opacity:0;font-size:1px;line-height:1px;color:#F4EFE9">You're now part of the {{brand_name}} community — here's what to expect.&#8203;&#8203;&#8203;&#8203;&#8203;&#8203;&#8203;&#8203;&#8203;&#8203;</div>
  <table role="presentation" width="100%" border="0" cellspacing="0" cellpadding="0" bgcolor="#F4EFE9" style="background-color:#F4EFE9">
    <tr><td align="center" style="padding:32px 12px">
      <!--[if mso]><table role="presentation" width="600" border="0" cellspacing="0" cellpadding="0"><tr><td><![endif]-->
      <table role="presentation" class="pgh-card" width="600" border="0" cellspacing="0" cellpadding="0" bgcolor="#FFFFFF" style="width:600px;max-width:600px;background-color:#FFFFFF;border-radius:10px;overflow:hidden;border:1px solid #ECE5DC">
<tr><td align="center" style="padding:34px 40px 22px 40px;border-bottom:1px solid #ECE5DC">
    <img src="{{logo_url}}" alt="{{brand_name}}" height="40" style="display:block;border:0;max-height:44px;width:auto" />
    <!--[if mso]>&nbsp;<![endif]-->
  </td></tr>
<tr><td style="padding:36px 40px 0px 40px"><div style="font-family:'Montserrat', 'Helvetica Neue', Arial, sans-serif;font-size:11px;font-weight:700;letter-spacing:3px;text-transform:uppercase;color:{{brand_color}}">Welcome to the house</div></td></tr>
<tr><td style="padding:12px 40px 0px 40px"><h1 style="margin:0;font-family:'Playfair Display', Georgia, 'Times New Roman', serif;font-size:30px;line-height:1.22;font-weight:600;color:#1A1212;letter-spacing:-0.2px">A warm welcome, {{first_name}}</h1></td></tr>
<tr><td style="padding:16px 40px 0px 40px"><p style="margin:0;font-family:'Montserrat', 'Helvetica Neue', Arial, sans-serif;font-size:15px;line-height:1.62;color:#1A1212">We're so glad you're here. {{brand_name}} is built on a simple belief — that the pieces you choose should feel considered, cared for, and made to last. Consider this your front-row seat.</p></td></tr>
<tr><td style="font-size:0;line-height:0;height:8px">&nbsp;</td></tr>
<tr><td style="padding:6px 40px">
    <table role="presentation" border="0" cellspacing="0" cellpadding="0"><tr>
      <td valign="top" style="font-size:16px;padding-right:12px;color:{{brand_color}}">✦</td>
      <td style="font-family:'Montserrat', 'Helvetica Neue', Arial, sans-serif;font-size:14px;line-height:1.5;color:#1A1212"><b>Curated quality</b> — every piece chosen with intention, never filler.</td>
    </tr></table>
  </td></tr>
<tr><td style="padding:6px 40px">
    <table role="presentation" border="0" cellspacing="0" cellpadding="0"><tr>
      <td valign="top" style="font-size:16px;padding-right:12px;color:{{brand_color}}">✦</td>
      <td style="font-family:'Montserrat', 'Helvetica Neue', Arial, sans-serif;font-size:14px;line-height:1.5;color:#1A1212"><b>Concierge care</b> — real people, ready when you need us.</td>
    </tr></table>
  </td></tr>
<tr><td style="padding:6px 40px">
    <table role="presentation" border="0" cellspacing="0" cellpadding="0"><tr>
      <td valign="top" style="font-size:16px;padding-right:12px;color:{{brand_color}}">✦</td>
      <td style="font-family:'Montserrat', 'Helvetica Neue', Arial, sans-serif;font-size:14px;line-height:1.5;color:#1A1212"><b>Member-first offers</b> — you'll hear about the good things first.</td>
    </tr></table>
  </td></tr>
<tr><td align="center" style="padding:30px 40px 8px 40px">
    <!--[if mso]><v:roundrect xmlns:v="urn:schemas-microsoft-com:vml" xmlns:w="urn:schemas-microsoft-com:office:word" href="{{website_url}}" style="height:50px;v-text-anchor:middle;width:280px;" arcsize="9%" strokecolor="{{brand_color}}" fillcolor="{{brand_color}}"><w:anchorlock/><center style="color:#ffffff;font-family:'Montserrat', 'Helvetica Neue', Arial, sans-serif;font-size:14px;font-weight:700;letter-spacing:1.5px;">Explore the collection</center></v:roundrect><![endif]-->
    <!--[if !mso]><!-- -->
