      &nbsp;·&nbsp;
      <a href="mailto:{{support_email}}" style="color:#7A7068;text-decoration:none">{{support_email}}</a>
    </div>
    <div style="font-family:'Montserrat', 'Helvetica Neue', Arial, sans-serif;font-size:11px;line-height:1.7;color:#A89F96;margin-top:16px">
      You're receiving this because you're part of the {{brand_name}} community.<br/>
      <a href="{{unsubscribe_url}}" target="_blank" style="color:#A89F96;text-decoration:underline">Unsubscribe</a>
      &nbsp;·&nbsp; © {{year}} {{brand_legal_name}}
    </div>
  </td></tr>
      </table>
      <!--[if mso]></td></tr></table><![endif]-->
    </td></tr>
  </table>
</body>
</html>$pgh$;
